import React from 'react'
import { Bicy } from "../components/data/Bicy";
import { Link } from 'react-router-dom'


function Bicycles() {
    return (
        <div className="Bicyc">
             <ul class="lightrope">
                <li></li><li></li><li></li><li></li><li></li><li></li>
            </ul>
            {Bicy.map(element => (
                <Link to={"p/" + element.id}  className="Bicyc__card">
                <div key={element.id}>
                    <div className="skid">{element.skid}</div>
                    <img src={element.img} alt={element.title} />
                    <h1>{element.title}</h1>
                    <p><div className="cost"> Цена:</div> {element.cost}</p>
                  
                </div>
                </Link>
            ))}
        </div>
    );
}

export default Bicycles;
